findings.recommendation:
Enforce in both parser and writer: (1) path.resolve(outputPath, filePath), (2) verify resolved path startsWith(path.resolve(outputPath)), (3) reject paths containing null bytes, (4) reject absolute paths, (5) reject paths with '..' segments before normalization as an additional check. Example:

function safePath(outputPath, filePath) {
  if (filePath.includes('\0')) throw new Error('Null byte in path');
  if (path.isAbsolute(filePath)) throw new Error('Absolute path rejected');
  const resolved = path.resolve(outputPath, filePath);
  if (!resolved.startsWith(path.resolve(outputPath) + path.sep)) {
    throw new Error('Path traversal detected');
  }
  return resolved;
}

Validate template ID against a whitelist of known template IDs before constructing file paths. Example:

const VALID_TEMPLATES = ['landing-page', 'telegram-bot', ...];
if (!VALID_TEMPLATES.includes(templateId)) throw new Error('Invalid template');
const configPath = path.join(TEMPLATES_DIR, `${templateId}.json`);
